 * BIDS specification for behavioral data:
 * https://bids-specification.readthedocs.io/en/stable/modality-specific-files/behavioral-data.html
 * 
 * @module BIDSDataSchema
 * @version 0.1.0
 */

import { z } from 'zod';

/**
 * BIDS event file schema
 * Required columns: onset, duration
 * Recommended: trial_type, response_time, stim_file
 */
export const BIDSEventSchema = z.object({
  // Required BIDS columns
