    const migratedData = migration(data);
    return BIDSDataTransformer.validate(migratedData);
  }
}

// Export convenience functions
export function createDataExport(
  experiment: PsyforgeDataExport['experiment'],
  events: BIDSEvent[],
  options: Partial<PsyforgeDataExport> = {}
): PsyforgeDataExport {
  const now = new Date();

  return {
    schemaVersion: '0.1.0',
    exportVersion: '1.0.0',
    exportDate: now.toISOString(),
    experiment,
    platform: {
      name: 'Psycho-Forge',
      version: '1.0.0',
      userAgent: typeof navigator !== 'undefined' ? navigator.userAgent : 'Unknown',
      screenResolution: {
        width: typeof window !== 'undefined' ? window.screen.width : 0,
        height: typeof window !== 'undefined' ? window.screen.height : 0
      },
      devicePixelRatio: typeof window !== 'undefined' ? window.devicePixelRatio : 1,
      refreshRate: undefined // Would need to be measured
    },
    participant: {
      participant_id: 'unknown'
    },
    session: {
      session_id: '001',
      date: now.toISOString().split('T')[0]
    },
    events,
    summary: {
      totalTrials: events.length,
      completedTrials: events.filter(e => e.response !== undefined).length,
      totalDuration: events.length > 0 
        ? Math.max(...events.map(e => e.onset + e.duration))
        : 0,
      overallAccuracy: events.length > 0
        ? events.filter(e => e.accuracy !== undefined).reduce((sum, e) => sum + (e.accuracy || 0), 0) / events.filter(e => e.accuracy !== undefined).length
        : undefined,
      meanResponseTime: events.length > 0
        ? events.filter(e => e.response_time !== undefined).reduce((sum, e) => sum + (e.response_time || 0), 0) / events.filter(e => e.response_time !== undefined).length
        : undefined
    },
    ...options
  };
}

