/**
 * Data collection and management for experiments
 * 
 * This module provides utilities for collecting, storing, and exporting
 * experimental data in a BIDS-compatible format.
 * 
 * @module DataCollector
 */

import type { TimelineContext } from '../core/Timeline.js';
import type { KeyboardResponseData } from '../responses/KeyboardResponse.js';
import type { MouseResponseData } from '../responses/MouseResponse.js';
import type { TouchResponseData } from '../responses/TouchResponse.js';
import type { BIDSEvent, PsyforgeDataExport } from './BIDSDataSchema.js';
import { createDataExport, BIDSDataTransformer } from './BIDSDataSchema.js';
import { timestampToNumber } from '../utils/timing.js';

export interface TrialData {
  trialIndex: number;
  blockIndex?: number;
  condition?: string;
  stimulusType?: string;
  stimulusContent?: string;
  stimulusOnset?: number;
  stimulusDuration?: number;
  responseData?: KeyboardResponseData | MouseResponseData | TouchResponseData;
  customData?: Record<string, unknown>;
}

export interface BlockData {
  blockIndex: number;
  blockType?: string;
  trials: TrialData[];
  startTime: number;
  endTime?: number;
  customData?: Record<string, unknown>;
}

/**
 * Collects and manages experimental data
 */
export class DataCollector {
  private experimentStartTime: number = 0;
  private blocks: BlockData[] = [];
  private currentBlock?: BlockData;
  private currentTrial?: TrialData;
  private metadata: Record<string, unknown> = {};
  private participantInfo: Record<string, unknown> = {};
  private sessionInfo: Record<string, unknown> = {};
  private qualityMetrics = {
    missedFrames: 0,
    droppedResponses: 0,
    timingPrecision: 2.0 // Default estimate in ms
  };

  constructor() {
    this.reset();
  }

  /**
   * Reset the data collector
   */
  reset(): void {
    this.experimentStartTime = 0;
    this.blocks = [];
    this.currentBlock = undefined;
    this.currentTrial = undefined;
    this.metadata = {};
    this.participantInfo = {};
    this.sessionInfo = {};
    this.qualityMetrics = {
      missedFrames: 0,
      droppedResponses: 0,
      timingPrecision: 2.0
    };
  }

  /**
   * Start the experiment
   */
  startExperiment(context: TimelineContext): void {
    this.experimentStartTime = timestampToNumber(context.clock.now());
    this.reset();
  }

  /**
   * Start a new block
   */
  startBlock(blockIndex: number, blockType?: string, customData?: Record<string, unknown>): void {
    // End current block if exists
    if (this.currentBlock) {
      this.endBlock();
    }

    this.currentBlock = {
      blockIndex,
      blockType,
      trials: [],
      startTime: Date.now(),
      customData
    };
  }

  /**
   * End the current block
   */
  endBlock(): void {
    if (this.currentBlock) {
      this.currentBlock.endTime = Date.now();
      this.blocks.push(this.currentBlock);
      this.currentBlock = undefined;
    }
  }

  /**
   * Start a new trial
   */
  startTrial(
    trialIndex: number,
    condition?: string,
    customData?: Record<string, unknown>
  ): void {
    this.currentTrial = {
      trialIndex,
      blockIndex: this.currentBlock?.blockIndex,
      condition,
      customData
    };
  }

  /**
   * Record stimulus presentation
   */
  recordStimulus(
    stimulusType: string,
    stimulusContent: string,
    onset: number,
    duration?: number
  ): void {
    if (this.currentTrial) {
      this.currentTrial.stimulusType = stimulusType;
      this.currentTrial.stimulusContent = stimulusContent;
      this.currentTrial.stimulusOnset = onset;
      this.currentTrial.stimulusDuration = duration;
    }
  }

  /**
   * Record a response
   */
  recordResponse(
    responseData: KeyboardResponseData | MouseResponseData | TouchResponseData
  ): void {
    if (this.currentTrial) {
      this.currentTrial.responseData = responseData;
    }
  }

  /**
   * End the current trial and store it
   */
  endTrial(): void {
    if (this.currentTrial && this.currentBlock) {
      this.currentBlock.trials.push(this.currentTrial);
      this.currentTrial = undefined;
    }
  }

  /**
   * Set participant information
   */
  setParticipantInfo(info: Record<string, unknown>): void {
    this.participantInfo = { ...this.participantInfo, ...info };
  }

  /**
   * Set session information
   */
  setSessionInfo(info: Record<string, unknown>): void {
    this.sessionInfo = { ...this.sessionInfo, ...info };
  }

  /**
   * Set experiment metadata
   */
  setMetadata(metadata: Record<string, unknown>): void {
    this.metadata = { ...this.metadata, ...metadata };
  }

  /**
   * Update quality metrics
   */
  updateQualityMetrics(metrics: Partial<typeof this.qualityMetrics>): void {
    this.qualityMetrics = { ...this.qualityMetrics, ...metrics };
  }

  /**
   * Convert collected data to BIDS events format
   */
  private toBIDSEvents(): BIDSEvent[] {
    const events: BIDSEvent[] = [];

    // Ensure current block is included
    if (this.currentBlock) {
      this.endBlock();
    }

    for (const block of this.blocks) {
      for (const trial of block.trials) {
        const onset = trial.stimulusOnset 
          ? (trial.stimulusOnset - this.experimentStartTime) / 1000 
          : 0;

        const duration = trial.stimulusDuration 
          ? trial.stimulusDuration / 1000 
          : 0;

        const responseTime = trial.responseData && 'reactionTime' in trial.responseData
          ? trial.responseData.reactionTime / 1000
          : undefined;

        const event: BIDSEvent = {
          onset,
          duration,
          trial_type: trial.condition,
          response_time: responseTime,
          stim_file: trial.stimulusContent,
          response: trial.responseData 
            ? ('key' in trial.responseData ? trial.responseData.key :
               'button' in trial.responseData ? trial.responseData.button :
               'action' in trial.responseData ? trial.responseData.action : 
               undefined)
            : undefined,
          accuracy: trial.responseData && 'correct' in trial.responseData
            ? (trial.responseData.correct ? 1 : 0)
            : undefined,
          trial_index: trial.trialIndex,
          block_index: trial.blockIndex,
          condition: trial.condition,
          stim_type: trial.stimulusType,
          stim_duration: trial.stimulusDuration ? trial.stimulusDuration / 1000 : undefined,
          timestamp: trial.stimulusOnset,
          metadata: trial.customData
        };

        events.push(event);
      }
    }

    return events;
  }

  /**
   * Export collected data
   */
  exportData(experimentInfo: PsyforgeDataExport['experiment']): PsyforgeDataExport {
    const events = this.toBIDSEvents();

    return createDataExport(experimentInfo, events, {
      participant: this.participantInfo as any,
      session: this.sessionInfo as any,
      quality: this.qualityMetrics,
      customData: this.metadata
    });
  }

  /**
   * Export data in different formats
   */
  exportAs(
    experimentInfo: PsyforgeDataExport['experiment'],
    format: 'json' | 'csv' | 'tsv' = 'json'
  ): string {
    const data = this.exportData(experimentInfo);
    return BIDSDataTransformer.export(data, format);
  }

  /**
   * Get summary statistics
   */
  getSummary(): PsyforgeDataExport['summary'] {
    const allTrials = this.blocks.flatMap(b => b.trials);
    const completedTrials = allTrials.filter(t => t.responseData !== undefined);
    const accuracies = completedTrials
      .filter(t => t.responseData && 'correct' in t.responseData)
      .map(t => t.responseData!.correct ? 1 : 0);
    const responseTimes = completedTrials
      .filter(t => t.responseData && 'reactionTime' in t.responseData)
      .map(t => (t.responseData as any).reactionTime / 1000);

    const totalDuration = this.blocks.reduce((sum, block) => {
      const blockDuration = (block.endTime || Date.now()) - block.startTime;
      return sum + blockDuration;
    }, 0) / 1000;

    return {
      totalTrials: allTrials.length,
      completedTrials: completedTrials.length,
      totalDuration,
      overallAccuracy: accuracies.length > 0
        ? accuracies.reduce((sum, acc) => sum + acc, 0) / accuracies.length
        : undefined,
      meanResponseTime: responseTimes.length > 0
        ? responseTimes.reduce((sum, rt) => sum + rt, 0) / responseTimes.length
        : undefined,
      blockCount: this.blocks.length
    };
  }

  /**
   * Integrate with timeline context
   */
  static fromContext(context: TimelineContext): DataCollector {
    const collector = new DataCollector();

    // Extract responses from context
    if (context.data.responses && Array.isArray(context.data.responses)) {
      context.data.responses.forEach((response, index) => {
        collector.startTrial(index);
        collector.recordResponse(response as any);
        collector.endTrial();
      });
    }

    // Extract collected data events
    if (context.data.collectedData && Array.isArray(context.data.collectedData)) {
      context.data.collectedData.forEach((data: any) => {
        // Merge custom collected data
        if (data.eventId && data.timestamp) {
          collector.setMetadata(data);
        }
      });
    }

    return collector;
  }
}

/**
 * Helper function to create a data collection event
 */
export function createDataCollectionEvent(
  id: string,
  collector: (context: TimelineContext) => Record<string, unknown>
): (context: TimelineContext) => void {
  return (context: TimelineContext) => {
    const data = collector(context);

    if (!context.data.collectedData) {
      context.data.collectedData = [];
    }

    (context.data.collectedData as Record<string, unknown>[]).push({
      eventId: id,
      timestamp: timestampToNumber(context.clock.now()),
      ...data
    });
  };
}

