/**
 * Export experiment data in BIDS-compatible format
 * @param format - Export format ('json', 'csv', or 'tsv')
 * @returns Formatted data string
 */
exportData(format: 'json' | 'csv' | 'tsv' = 'json'): string {
  if (!this.experimentData) {
    throw new Error('No experiment data available. Run the experiment first.');
  }

  // Create a data collector from the context
  const collector = new DataCollector();

  // Set participant and session info
  if (this.experimentData.participantId) {
    collector.setParticipantInfo({ participant_id: this.experimentData.participantId });
  }
  collector.setSessionInfo({ 
    session_id: this.experimentData.sessionId,
    date: new Date(this.experimentData.startTime).toISOString().split('T')[0]
  });

  // Set metadata
  collector.setMetadata(this.experimentData.metadata);

  // Process responses and collected data
  if (this.experimentData.responses) {
    this.experimentData.responses.forEach((response: any, index) => {
      collector.startTrial(index);
      if (response) {
        collector.recordResponse(response);
      }
      collector.endTrial();
    });
  }

  // Export the data
  const experimentInfo: PsyforgeDataExport['experiment'] = {
    name: this.metadata.title,
    version: this.metadata.version,
    description: this.metadata.description,
    doi: this.metadata.doi,
    author: this.metadata.author,
    institution: this.metadata.institution
  };

  return collector.exportAs(experimentInfo, format);
}

/**
 * Export data in BIDS format
 * @returns BIDS-formatted data structure
 */
exportBIDS(): ReturnType<typeof BIDSDataTransformer.toBIDS> {
  if (!this.experimentData) {
    throw new Error('No experiment data available. Run the experiment first.');
  }

  const jsonData = this.exportData('json');
  const parsedData = JSON.parse(jsonData);
  return BIDSDataTransformer.toBIDS(parsedData);
}

/**
 * Get experiment results summary
 * @returns Summary statistics of the experiment
 */
getResults(): PsyforgeDataExport['summary'] | undefined {
  if (!this.experimentData) {
    return undefined;
  }

  const collector = new DataCollector();

  // Process responses to get summary
  if (this.experimentData.responses) {
    this.experimentData.responses.forEach((response: any, index) => {
      collector.startTrial(index);
      if (response) {
        collector.recordResponse(response);
      }
      collector.endTrial();
    });
  }

  return collector.getSummary();
}

