} from '../BIDSDataSchema.js';

describe('BIDS Data Schema', () => {
  describe('BIDSEventSchema', () => {
    it('should validate required fields', () => {
      const validEvent = {
        onset: 1.5,
        duration: 2.0
      };

      const result = BIDSEventSchema.parse(validEvent);
      expect(result.onset).toBe(1.5);
      expect(result.duration).toBe(2.0);
    });

    it('should validate optional fields', () => {
