      expect(result.accuracy).toBe(1);
    });

    it('should reject invalid accuracy values', () => {
      const invalidEvent = {
        onset: 1.5,
        duration: 2.0,
        accuracy: 1.5 // Invalid: > 1
      };

      expect(() => BIDSEventSchema.parse(invalidEvent)).toThrow();
    });
  });

