      const invalidParticipant = {
        participant_id: 'participant-001' // Invalid format
      };

      expect(() => BIDSParticipantSchema.parse(invalidParticipant)).toThrow();
    });
  });

  describe('BIDSSessionSchema', () => {
    it('should validate BIDS session format', () => {
      const validSession = {
        session_id: 'ses-01',
        date: '2025-07-10',
        time: '14:30:00',
        experimenter: 'Dr. Smith',
        lab: 'Cognitive Lab A'
      };

      const result = BIDSSessionSchema.parse(validSession);
      expect(result.session_id).toBe('ses-01');
      expect(result.date).toBe('2025-07-10');
    });
  });

  describe('BIDSDataTransformer', () => {
    const sampleData: PsyforgeDataExport = {
      schemaVersion: '0.1.0',
      exportVersion: '1.0.0',
      exportDate: '2025-07-10T12:00:00Z',
      experiment: {
        name: 'Stroop Task',
        version: '1.0.0',
        description: 'Classic Stroop color-word interference task'
      },
      platform: {
        name: 'Psycho-Forge',
        version: '1.0.0',
        userAgent: 'Mozilla/5.0',
        screenResolution: { width: 1920, height: 1080 },
        devicePixelRatio: 2,
        refreshRate: 144
      },
      participant: {
        participant_id: '001',
        age: 25,
        sex: 'male'
      },
      session: {
        session_id: '01',
        date: '2025-07-10'
      },
      events: [
        {
          onset: 0.5,
          duration: 2.0,
          trial_type: 'congruent',
          response_time: 0.650,
          response: 'f',
          accuracy: 1
        },
        {
          onset: 3.0,
          duration: 2.0,
          trial_type: 'incongruent',
          response_time: 0.780,
          response: 'g',
          accuracy: 1
        }
      ],
      summary: {
        totalTrials: 2,
        completedTrials: 2,
        totalDuration: 5.0,
        overallAccuracy: 1.0,
        meanResponseTime: 0.715
      }
    };

    it('should transform to BIDS format', () => {
      const bidsData = BIDSDataTransformer.toBIDS(sampleData);

      expect(bidsData.participants.participant_id).toBe('sub-001');
      expect(bidsData.sessions.session_id).toBe('ses-01');
      expect(bidsData.events).toHaveLength(2);
      expect(bidsData.taskMetadata.TaskName).toBe('Stroop Task');
    });

    it('should validate data', () => {
      const validated = BIDSDataTransformer.validate(sampleData);
      expect(validated.schemaVersion).toBe('0.1.0');
      expect(validated.events).toHaveLength(2);
    });

    it('should export as JSON', () => {
      const json = BIDSDataTransformer.export(sampleData, 'json');
      const parsed = JSON.parse(json);
      expect(parsed.schemaVersion).toBe('0.1.0');
      expect(parsed.events).toHaveLength(2);
    });

    it('should export as CSV', () => {
      const csv = BIDSDataTransformer.export(sampleData, 'csv');
      const lines = csv.split('\n');
      expect(lines).toHaveLength(3); // Header + 2 data rows
      expect(lines[0]).toContain('onset');
      expect(lines[0]).toContain('duration');
      expect(lines[0]).toContain('trial_type');
    });

    it('should export as TSV', () => {
      const tsv = BIDSDataTransformer.export(sampleData, 'tsv');
      const lines = tsv.split('\n');
      expect(lines).toHaveLength(3); // Header + 2 data rows
      expect(lines[0]).toContain('\t'); // Tab-separated
      expect(lines[1]).toContain('\t');
    });
  });

  describe('DataSchemaMigration', () => {
    it('should register and apply migrations', () => {
      const oldData = {
        schemaVersion: '0.0.1',
        title: 'Old Experiment',
        trials: []
      };

      const newData: PsyforgeDataExport = {
        schemaVersion: '0.1.0',
        exportVersion: '1.0.0',
        exportDate: new Date().toISOString(),
        experiment: {
          name: 'Old Experiment',
          version: '1.0.0'
        },
        platform: {
          name: 'Psycho-Forge',
          version: '1.0.0',
          userAgent: 'Unknown',
          screenResolution: { width: 0, height: 0 },
          devicePixelRatio: 1
        },
        participant: { participant_id: 'unknown' },
        session: { session_id: '001', date: '2025-01-01' },
        events: [],
        summary: {
          totalTrials: 0,
          completedTrials: 0,
          totalDuration: 0
        }
      };

      DataSchemaMigration.registerMigration('0.0.1', '0.1.0', (data) => newData);

      const migrated = DataSchemaMigration.migrate(oldData, '0.1.0');
      expect(migrated.schemaVersion).toBe('0.1.0');
      expect(migrated.experiment.name).toBe('Old Experiment');
    });

    it('should handle missing migration paths', () => {
      const data = {
        schemaVersion: '0.0.2',
        title: 'Test'
      };

      expect(() => DataSchemaMigration.migrate(data, '0.1.0')).toThrow(
        'No migration path from version 0.0.2 to 0.1.0'
      );
    });
  });

  describe('createDataExport', () => {
    it('should create a valid data export', () => {
      const events: BIDSEvent[] = [
        {
          onset: 1.0,
          duration: 2.0,
          trial_type: 'test',
          response: 'space',
          accuracy: 1
        }
      ];

      const experiment = {
        name: 'Test Experiment',
        version: '1.0.0',
        author: 'Test Author'
      };

      const data = createDataExport(experiment, events, {
        participant: { participant_id: 'test-001' }
      });

      expect(data.schemaVersion).toBe('0.1.0');
      expect(data.experiment.name).toBe('Test Experiment');
      expect(data.events).toHaveLength(1);
      expect(data.participant.participant_id).toBe('test-001');
      expect(data.summary.totalTrials).toBe(1);
      expect(data.summary.overallAccuracy).toBe(1);
    });
  });
});

