await exp.run('participant-001');

// Export data in different formats
const jsonData = exp.exportData('json');
const csvData = exp.exportData('csv');
const tsvData = exp.exportData('tsv');

// Get BIDS-formatted data
const bidsData = exp.exportBIDS();
```

### Using DataCollector Directly

```typescript
import { DataCollector } from '@psyforge/forgescript';

const collector = new DataCollector();

// Start experiment
collector.startExperiment(context);

// Record block
collector.startBlock(0, 'practice');

// Record trial
collector.startTrial(0, 'congruent');
collector.recordStimulus('text', 'RED', 1000, 2000);
collector.recordResponse({
  key: 'f',
  timestamp: 1450,
  reactionTime: 450,
  correct: true
});
collector.endTrial();

collector.endBlock();

// Export data
const data = collector.exportData({
  name: 'Stroop Task',
  version: '1.0.0'
});
```

### Custom Data Collection

```typescript
import { createDataCollectionEvent } from '@psyforge/forgescript';

// Create custom data collection event
const collectTrialData = createDataCollectionEvent('trial-data', (context) => ({
  condition: context.data.condition,
  stimulusColor: context.data.color,
  responseKey: context.data.lastResponse,
  customMetric: calculateMetric(context)
}));

// Use in timeline
timeline.add(collectTrialData);
```

